INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(1,'Cookie Butter Cupcake','cupcakes','A rich and flavorful cupcake infused with the warm, spiced taste of cookie butter. Topped with smooth cookie butter frosting and a drizzle for extra indulgence, this cupcake is perfect for anyone who loves the sweet, caramelized flavor of cookie butter. A delicious treat for any occasion.','gallery/1773503874865-ea02bbc6737a5d0402180e6e4818e0ce.jpeg','ea02bbc6737a5d0402180e6e4818e0ce.jpeg','image/jpeg',36041,0,'2026-03-14T15:57:55.246Z','2026-03-14T16:20:28.093Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(2,'Heart-Shaped Edible Image Cake','cakes','A beautiful heart-shaped cake featuring customizable edible images. Perfect for birthdays, anniversaries, or any special celebration. Personalize the design and message to fit your occasion','gallery/1773503940919-c15978c7ca142a8570013b9854656335.jpeg','c15978c7ca142a8570013b9854656335.jpeg','image/jpeg',56532,0,'2026-03-14T15:59:01.228Z','2026-03-14T16:16:49.238Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(3,'Homemade Cookies','cookies','Soft, fresh, and baked from scratch, these homemade cookies are full of rich flavor and comforting sweetness. Made with quality ingredients and available in a variety of flavors, they’re perfect for dessert tables, gifts, or simply satisfying your sweet tooth.','gallery/1773503978561-44f197c6c714a0eeaf41fbead5395d3a.jpeg','44f197c6c714a0eeaf41fbead5395d3a.jpeg','image/jpeg',17366,0,'2026-03-14T15:59:38.899Z','2026-03-14T16:15:00.706Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(4,'1/4 Sheet Cake','cakes','Our 1/4 sheet cakes are perfect for small gatherings, birthdays, office celebrations, or any special occasion. Baked fresh and customized to your liking, each cake features moist layers and smooth, delicious frosting with your choice of colors, message, or theme. Serves approximately 15–20 people.','gallery/1773573895312-49ddaed3bce4156fd3a828f3248b8c79.jpeg','49ddaed3bce4156fd3a828f3248b8c79.jpeg','image/jpeg',60167,0,'2026-03-15T11:24:55.611Z','2026-03-15T11:24:55.611Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(5,' Bento Cake Box','cakes','Our Bento Cake Box is the perfect sweet treat for birthdays, date nights, small celebrations, or just because. Each box includes a mini personalized cake paired with delicious cupcakes, beautifully decorated and packaged in a convenient bento-style box. Customize the colors, message, and theme to match your special occasion. Perfect for gifting or celebrating with a small group','gallery/1773574036533-9502ad205d9010e7d613d7e2d03fd1b7.jpeg','9502ad205d9010e7d613d7e2d03fd1b7.jpeg','image/jpeg',75178,0,'2026-03-15T11:27:16.821Z','2026-03-15T11:27:16.821Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(6,'Lemon Poundcake','cakes','A rich, buttery homemade pound cake infused with fresh lemon flavor and baked to golden perfection. This moist, dense cake is finished with a light lemon glaze that adds the perfect balance of sweet and citrusy. A refreshing classic that’s perfect for any occasion or simply enjoying with a cup of coffee or tea','gallery/1773578327879-IMG_3212.jpeg','IMG_3212.jpeg','image/jpeg',103651,0,'2026-03-15T12:38:48.174Z','2026-03-15T12:38:48.174Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(7,'German Chocolate Cake','cakes','A classic, rich chocolate cake layered with our signature homemade coconut pecan frosting. This decadent dessert features moist chocolate cake paired with a sweet, buttery filling loaded with toasted coconut and crunchy pecans. A timeless favorite that’s perfect for celebrations or anytime you’re craving a truly indulgent slice.','gallery/1773579064577-IMG_3213.jpeg','IMG_3213.jpeg','image/jpeg',206449,0,'2026-03-15T12:51:04.868Z','2026-03-15T12:51:04.868Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(8,'Strawberry Crunch Cake','cakes','A moist strawberry cake layered with smooth cream cheese frosting and coated with our signature strawberry crunch topping for the perfect sweet and crunchy finish. Inspired by the classic strawberry crunch ice cream bar, this cake is a fun and flavorful treat that’s perfect for birthdays, celebrations, or any strawberry lover','gallery/1773579603737-IMG_3214.jpeg','IMG_3214.jpeg','image/jpeg',214977,0,'2026-03-15T13:00:04.067Z','2026-03-15T13:00:04.067Z');
INSERT INTO "gallery_images" ("id","title","category","description","r2_key","filename","content_type","size","is_featured","created_at","updated_at") VALUES(9,'Red Velvet Cupcakes','cupcakes','Our Red Velvet Cupcake is a classic favorite, featuring a soft, moist crumb with signature deep red color. Baked to perfection, this cupcake offers a rich yet balanced flavor with a subtle tang that makes every bite smooth and indulgent. It’s topped with a generous swirl of our silky cream cheese frosting, creating the perfect blend of sweet and tangy.','gallery/1773616686907-Image.jpeg','Image.jpeg','image/jpeg',143454,0,'2026-03-15T23:18:07.246Z','2026-03-15T23:18:34.632Z');
